record.field:
# OpenTelemetry Collector configuration # Receives OTLP (gRPC 4317 / HTTP 4318), batches, and exports. # Replace the 'debug' exporter with real backends (prometheus, loki, otlphttp, ...).
receivers: otlp: protocols: grpc: endpoint: 0.0.0.0:4317 http: endpoint: 0.0.0.0:4318
processors: memory_limiter: check_interval: 5s limit_percentage: 80 spike_limit_percentage: 25 batch: {}
exporters: # Safe default: logs telemetry so the collector boots without an external backend. debug: verbosity: {{ debug_verbosity | default('normal') }}
extensions: health_check: endpoint: 0.0.0.0:13133
service: extensions: [health_check] pipelines: traces: receivers: [otlp] processors: [memory_limiter, batch] exporters: [debug] metrics: receivers: [otlp] processors: [memory_limiter, batch] exporters: [debug] logs: receivers: [otlp] processors: [memory_limiter, batch] exporters: [debug]
